#!/usr/bin/env bash
# ═══════════════════════════════════════════════════════════════
#  NOVA CLI — Installer
#  curl -sSL https://raw.githubusercontent.com/TU_USER/nova-os/main/install.sh | bash
#  curl -sSL https://TU_IP:3005/install | bash
#
#  Self-contained — nova.py está embebido.
#  No requiere internet después de ejecutar este script.
# ═══════════════════════════════════════════════════════════════
set -e

NOVA_VERSION="2.0.0"
NOVA_DIR="$HOME/.nova"
NOVA_PY="$NOVA_DIR/nova.py"

# ── Colors ──────────────────────────────────────────────────────
if [ -t 1 ] && [ -z "${NO_COLOR}" ]; then
  B0='\033[38;5;17m' B4='\033[38;5;21m' B7='\033[38;5;39m'
  W='\033[1;97m' G1='\033[38;5;245m' G3='\033[38;5;238m'
  GRN='\033[38;5;84m' RED='\033[38;5;196m' YLW='\033[38;5;220m'
  BD='\033[1m' R='\033[0m'
else
  B0='' B4='' B7='' W='' G1='' G3='' GRN='' RED='' YLW='' BD='' R=''
fi

ok()   { echo -e "  ${GRN}✓${R}  $1"; }
fail() { echo -e "  ${RED}✗${R}  $1"; exit 1; }
info() { echo -e "  ${B7}·${R}  ${G1}$1${R}"; }
dim()  { echo -e "  ${G3}  $1${R}"; }

# ── Logo ────────────────────────────────────────────────────────
clear 2>/dev/null || true
echo ""
echo -e "  ${B0}${BD}  ███╗   ██╗ ██████╗ ██╗   ██╗ █████╗  ${R}"
echo -e "  ${B4}${BD}  ████╗  ██║██╔═══██╗██║   ██║██╔══██╗ ${R}"
echo -e "  ${B4}${BD}  ██╔██╗ ██║██║   ██║██║   ██║███████║ ${R}"
echo -e "  ${B7}${BD}  ██║╚██╗██║██║   ██║╚██╗ ██╔╝██╔══██║ ${R}"
echo -e "  ${B7}${BD}  ██║ ╚████║╚██████╔╝ ╚████╔╝ ██║  ██║ ${R}"
echo -e "  ${B7}${BD}  ╚═╝  ╚═══╝ ╚═════╝   ╚═══╝  ╚═╝  ╚═╝ ${R}"
echo ""
echo -e "  ${G1}Nova CLI${R}  ${G3}·${R}  ${G3}Agents that answer for themselves.${R}"
echo -e "  ${G3}────────────────────────────────────────────${R}"
echo ""
echo -e "  ${W}Installing Nova CLI v${NOVA_VERSION}${R}"
echo ""

# ── Check Python ────────────────────────────────────────────────
PYTHON=""
for cmd in python3 python; do
  if command -v $cmd &>/dev/null; then
    VER=$($cmd -c "import sys; print(f'{sys.version_info.major}.{sys.version_info.minor}')" 2>/dev/null)
    MAJ=$($cmd -c "import sys; print(sys.version_info.major)" 2>/dev/null)
    MIN=$($cmd -c "import sys; print(sys.version_info.minor)" 2>/dev/null)
    if [ "$MAJ" -ge 3 ] && [ "$MIN" -ge 8 ] 2>/dev/null; then
      PYTHON=$cmd
      ok "Python ${VER}"
      break
    fi
  fi
done

if [ -z "$PYTHON" ]; then
  fail "Python 3.8+ no encontrado. Instálalo en python.org"
fi

# ── Crear directorio ─────────────────────────────────────────────
mkdir -p "$NOVA_DIR"
ok "Directorio: $NOVA_DIR"

# ── Escribir nova.py desde base64 embebido ────────────────────────
echo -e "  ${B4}○${R}  ${G1}Instalando nova.py...${R}" | tr -d '\n'
echo ""
printf '%s' "" | base64 -d > "$NOVA_PY"
chmod +x "$NOVA_PY"
ok "nova.py instalado"

# ── Instalar comando 'nova' ────────────────────────────────────────
install_cmd() {
  local target="$1"
  local dir="$(dirname $target)"
  mkdir -p "$dir"
  printf '#!/bin/bash\nexec %s "%s" ""\n' "$PYTHON" "$NOVA_PY" > "$target"
  chmod +x "$target"
}

INSTALLED_IN=""
CMD_PATH="/usr/local/bin/nova"

if [ -w "/usr/local/bin" ]; then
  install_cmd "$CMD_PATH"
  INSTALLED_IN="/usr/local/bin"
elif sudo -n true 2>/dev/null; then
  sudo bash -c "printf '#!/bin/bash\nexec $PYTHON \"$NOVA_PY\" \"$@\"\n' > '$CMD_PATH' && chmod +x '$CMD_PATH'"
  INSTALLED_IN="/usr/local/bin"
else
  CMD_PATH="$NOVA_DIR/nova"
  install_cmd "$CMD_PATH"
  INSTALLED_IN="$NOVA_DIR"
fi

ok "Comando 'nova' instalado en $INSTALLED_IN"

# ── Agregar al PATH si es necesario ──────────────────────────────
if [ "$INSTALLED_IN" = "$NOVA_DIR" ]; then
  SHELL_RC="$HOME/.bashrc"
  [ -n "$ZSH_VERSION" ] && SHELL_RC="$HOME/.zshrc"
  [ -f "$HOME/.bash_profile" ] && [ ! -f "$HOME/.bashrc" ] && SHELL_RC="$HOME/.bash_profile"

  if ! grep -q "\.nova" "$SHELL_RC" 2>/dev/null; then
    echo "" >> "$SHELL_RC"
    echo "# Nova CLI" >> "$SHELL_RC"
    echo "export PATH=\"$PATH:$NOVA_DIR\"" >> "$SHELL_RC"
    info "PATH actualizado en $SHELL_RC"
    info "Ejecuta: source $SHELL_RC"
  fi
fi

# ── Test ─────────────────────────────────────────────────────────
if "$PYTHON" "$NOVA_PY" --help &>/dev/null; then
  ok "Nova CLI funciona correctamente"
else
  fail "Algo salió mal. Intenta: python3 ~/.nova/nova.py help"
fi

# ── Summary ──────────────────────────────────────────────────────
echo ""
echo -e "  ${G3}────────────────────────────────────────────${R}"
echo ""
echo -e "  ${GRN}${BD}Nova CLI instalado ✓${R}"
echo ""
echo -e "  ${W}Próximos pasos:${R}"
echo ""
echo -e "  ${B7}nova init${R}           ${G3}# conecta con tu servidor${R}"
echo -e "  ${B7}nova agent create${R}   ${G3}# crea tu primer agente${R}"
echo -e "  ${B7}nova status${R}         ${G3}# verifica que todo funciona${R}"
echo -e "  ${B7}nova help${R}           ${G3}# todos los comandos${R}"
echo ""
